import { task, wait } from "@trigger.dev/sdk/v3";

const trial_id = "123";

export const approvalWorkflow = task({
  id: `approval-workflow-${trial_id}`,
  run: async (payload: any) => {
    const { data } = await wait.forToken<{ approved: boolean }>("manager-approval");
    return data;
  },
});

